import { useState } from "react";
import { motion } from "framer-motion";
import { Home, Users, FileText, ClipboardList, Activity, User } from "lucide-react";

const menuItems = [
    { name: "Dashboard", icon: Home },
    { name: "Patients", icon: Users },
    { name: "Tests", icon: ClipboardList },
    { name: "Billing", icon: FileText },
    { name: "Reports", icon: Activity },
    { name: "Doctors", icon: User },
];

export default function Dashboard() {
    const [patients, setPatients] = useState([]);
    const [name, setName] = useState("");
    const [active, setActive] = useState("Dashboard");

    const addPatient = () => {
        if (!name) return;
        setPatients([...patients, { name }]);
        setName("");
    };

    return (
        <div className="flex h-screen bg-gray-100">
            {/* Sidebar */}
            <div className="w-64 bg-gradient-to-b from-slate-900 to-slate-800 text-white p-4">
                <h1 className="text-xl font-bold mb-6">Lab Panel</h1>

                <div className="space-y-2">
                    {menuItems.map((item) => {
                        const Icon = item.icon;
                        const isActive = active === item.name;

                        return (
                            <div
                                key={item.name}
                                onClick={() => setActive(item.name)}
                                className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-all ${isActive
                                    ? "bg-white/10 text-white"
                                    : "text-gray-400 hover:bg-white/10 hover:text-white"
                                    }`}
                            >
                                <Icon size={18} />
                                <span>{item.name}</span>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Main Content */}
            <div className="flex-1 p-6 overflow-auto">
                <h1 className="text-2xl font-bold mb-4">{active}</h1>

                {active === "Dashboard" && (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                        <div className="bg-white p-4 rounded-xl shadow">
                            <p>This month's Registrations</p>
                            <h2 className="text-xl font-bold">{patients.length}</h2>
                        </div>
                        <div className="bg-white p-4 rounded-xl shadow">
                            <p>Bill of the month</p>
                            <h2 className="text-xl font-bold">Γé╣0</h2>
                        </div>
                        <div className="bg-white p-4 rounded-xl shadow">
                            <p>Collection of the month</p>
                            <h2 className="text-xl font-bold">0</h2>
                        </div>
                        <div className="bg-white p-4 rounded-xl shadow">
                            <p>Total Dues</p>
                            <h2 className="text-xl font-bold">0</h2>
                        </div>
                    </div>
                )}

                {active === "Patients" && (
                    <div className="bg-white p-4 rounded-xl shadow space-y-4">
                        <h2 className="text-lg font-semibold">Add Patient</h2>
                        <div className="flex gap-2">
                            <input
                                className="border p-2 rounded w-full"
                                placeholder="Enter patient name"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                            />
                            <button
                                onClick={addPatient}
                                className="bg-blue-600 text-white px-4 py-2 rounded"
                            >
                                Add
                            </button>
                        </div>

                        <div>
                            {patients.map((p, i) => (
                                <motion.div
                                    key={i}
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="p-2 border rounded mb-2"
                                >
                                    {p.name}
                                </motion.div>
                            ))}
                        </div>
                    </div>
                )}

                {active === "Tests" && (
                    <div className="bg-white p-4 rounded-xl shadow">
                        <h2 className="text-lg font-semibold">Test Management</h2>
                        <p>Coming soon...</p>
                    </div>
                )}

                {active === "Billing" && (
                    <div className="bg-white p-4 rounded-xl shadow">
                        <h2 className="text-lg font-semibold">Billing & Invoicing</h2>
                        <p>Coming soon...</p>
                    </div>
                )}

                {active === "Reports" && (
                    <div className="bg-white p-4 rounded-xl shadow">
                        <h2 className="text-lg font-semibold">Report Generation</h2>
                        <p>Coming soon...</p>
                    </div>
                )}

                {active === "Doctors" && (
                    <div className="bg-white p-4 rounded-xl shadow">
                        <h2 className="text-lg font-semibold">Doctor Management</h2>
                        <p>Coming soon...</p>
                    </div>
                )}
            </div>
        </div>
    );
}
